public async Task GetAllAsync_ShouldReturnListOfTodos()
{
    // Arrange
    var mockRepo = new Mock<ITodoRepository>();
    var expectedTodos = new List<Todo> { new Todo { Id = 1, Title = "Test" } };
    mockRepo.Setup(repo => repo.GetAllAsync()).ReturnsAsync(expectedTodos);
    var service = new TodoService(mockRepo.Object);

    // Act
    var result = await service.GetAllAsync();

    // Assert
    Assert.Equal(expectedTodos, result);
    mockRepo.Verify(repo => repo.GetAllAsync(), Times.Once);
}
